#include <iostream>

int main() {
    int a = 0, b = 0;
    for (int i = 1; i <= 3; i++) {
        for (int j = 1; j <= 4; j++) {
            if (i % 2 == 0) {
                a += j;
                b += i;
            } else {
                if (j % 2 == 0) {
                    a -= i;
                } else {
                    b += j;
                }
            }
        }
    }
    std::cout << "a = " << a << ", b = " << b << std::endl;
    return 0;
}

async function fetchAndExtract(urls, key) {
  const results = [];
  urls.forEach(async (url) => {
    const response = await fetch(url);
    const data = await response.json();
    results.push(data[key]);
  });
  return results;
}
